const email = $input.first().json;

// Check if email has attachments
const attachments = email.attachments ?? [];
const pdfAttachment = attachments.find(a =>
  a.mimeType === 'application/pdf' ||
  (a.filename ?? '').toLowerCase().endsWith('.pdf')
);

if (!pdfAttachment) {
  // No PDF — skip silently
  return [{ json: { skip: true, reason: 'No PDF attachment found', emailId: email.id, subject: email.subject } }];
}

return [{
  json: {
    skip: false,
    emailId:          email.id,
    emailSubject:     email.subject ?? 'No subject',
    emailFrom:        email.from ?? 'Unknown sender',
    emailDate:        email.date ?? $now.toISO(),
    attachmentName:   pdfAttachment.filename ?? 'invoice.pdf',
    attachmentData:   pdfAttachment.content,
    mimeType:         pdfAttachment.mimeType ?? 'application/pdf'
  }
}];

// Try to get text from Extract from File node first (production)
// Fall back to reading directly from attachment content (mock/testing)
let pdfText = '';

try {
  const fileData = $input.first().json;
  pdfText = fileData.text ?? fileData.data ?? '';
} catch(e) {
  pdfText = '';
}

// If extraction returned nothing, read directly from attachment content
if (!pdfText || pdfText.trim().length < 20) {
  const attachmentData = $('Code — Extract PDF Attachment').first().json;
  pdfText = attachmentData.attachmentData ?? '';
}

if (!pdfText || pdfText.trim().length < 20) {
  return [{
    json: {
      ...$('Code — Extract PDF Attachment').first().json,
      pdfText: '',
      extractionError: 'No text could be extracted from PDF'
    }
  }];
}

const attachmentData = $('Code — Extract PDF Attachment').first().json;

return [{
  json: {
    ...attachmentData,
    pdfText: pdfText.trim().substring(0, 8000)
  }
}];

const groqResponse = $input.first().json;
const emailData = $('Code — Prepare PDF Text').first().json;

const rawText = groqResponse?.choices?.[0]?.message?.content ?? '{}';
const cleaned = rawText.replace(/```json\s*/gi,'').replace(/```\s*/gi,'').trim();

let invoice;
try {
  invoice = JSON.parse(cleaned);
} catch(e) {
  invoice = {
    invoice_number: null, invoice_date: null, due_date: null,
    vendor_name: null, vendor_email: null, vendor_address: null,
    bill_to: null, subtotal: null, tax_amount: null, tax_rate: null,
    total_amount: null, currency: null, payment_terms: null,
    line_items: [], notes: 'JSON parse error: ' + e.message,
    confidence: 'Low'
  };
}

// Validation — check required fields
const requiredFields = ['vendor_name', 'total_amount', 'invoice_date'];
const missingFields = requiredFields.filter(f => !invoice[f]);
const isValid = missingFields.length === 0;

// Format line items as readable string for sheets
const lineItemsStr = (invoice.line_items ?? []).map(item =>
  `${item.description} x${item.quantity} @ ${item.unit_price} = ${item.total}`
).join(' | ');

return [{
  json: {
    // Email metadata
    email_id:          emailData.emailId,
    email_subject:     emailData.emailSubject,
    email_from:        emailData.emailFrom,
    email_date:        emailData.emailDate,
    attachment_name:   emailData.attachmentName,
    processed_at:      $now.toISO(),

    // Extracted invoice data
    invoice_number:    invoice.invoice_number,
    invoice_date:      invoice.invoice_date,
    due_date:          invoice.due_date,
    vendor_name:       invoice.vendor_name,
    vendor_email:      invoice.vendor_email,
    vendor_address:    invoice.vendor_address,
    bill_to:           invoice.bill_to,
    subtotal:          invoice.subtotal,
    tax_amount:        invoice.tax_amount,
    tax_rate:          invoice.tax_rate,
    total_amount:      invoice.total_amount,
    currency:          invoice.currency ?? 'USD',
    payment_terms:     invoice.payment_terms,
    line_items:        lineItemsStr,
    notes:             invoice.notes,
    confidence:        invoice.confidence,

    // Validation
    is_valid:          isValid,
    missing_fields:    missingFields.join(', ') || 'None',
    status:            isValid ? 'Processed' : 'Review Required'
  }
}];

